// Basic initialization -- all equivalent
int x = 5;
int y = { 5 };
int z = int { 5 };

// Array initialization
int a[3] = { 1, 2, 3 };        // a = [1, 2, 3]
int b[] = { 4, 5, 6 };         // size deduced as 3
int c[10] = { };                // all zeros
int d[10] = { 1, 2 };          // d = [1, 2, 0, 0, ..., 0]
int e[] = { 100 };             // size deduced as 1

// Pointer initialization with new
int *p = new int[3] {1, 2, 3};

class MyClass {
    int x;
public:
    MyClass();                       // Default constructor
    MyClass(int value);              // Parameterized constructor
    MyClass(const MyClass & obj);    // Copy constructor
    MyClass(MyClass && obj);         // Move constructor
};

void main() {
    Date d;                // constructor called
    Date *d2 = new Date(); // constructor called
    Date arr[100];         // constructor called 100 times!
    Date *d3;              // just a pointer -- NO constructor
}

class Object {
    int x, y, z;  // declaration order: x, y, z
public:
    Object(int value) : y(value), z(value/2), x(y*z) {}
    // DANGER: x is initialized FIRST (declaration order)
    // But y and z aren't set yet -> x = garbage * garbage!
};

class Date {
    int x;
    const int y;     // MUST be initialized in every constructor
    int & ref;       // MUST be initialized in every constructor
public:
    Date() : x(100), y(123), ref(x) { }           // OK
    Date(int v) : x(v), y(v*v), ref(x) { }        // OK
    // Date() : x(100) { y = 123; }  // ERROR: const in body!
};

// C++11: initialize at declaration
class Date2 {
    int x;
    const int y = 123;    // default, can be overridden
    int & ref = x;        // default reference
public:
    Date2() : x(100) { }  // y=123, ref=x by default
};

class Object {
    int x, y;
public:
    Object(int value) : x(value), y(value) {}
    Object() : Object(0) { }       // delegates to Object(int)
    // Object() : Object(0), y(1) {} // ERROR: can't mix!
};

// Can modify in body after delegation:
Object() : Object(0) { y = 1; }  // OK: y set to 0 by delegation, then 1

// Aggregate initialization -- public members, no constructor
struct Data {
    int x;
    char t;
    const char* m;
};

void main() {
    Data d1{ 10, 'A', "test" };        // OK
    Data d2 = { 5, 'B', "C++" };       // OK
    Data d3{};                          // zero-initialization: x=0, t=0, m=nullptr
}

int a = 10 + 20 + 30;
// 10, 20, 30 are prvalues (just values)
// 10+20 = Temp1 (xvalue -- temporary)
// Temp1+30 = Temp2 (xvalue -- temporary)
// a is a glvalue (has memory address)

int b;
b = (a += 20) + 10;
// a, b are lvalues (and glvalues)
// 20, 10 are prvalues (and rvalues)
// a++ is a prvalue (returns old copy)
// ++a is a glvalue (returns reference)

class Date {
    char * sir;
public:
    // Copy constructor -- deep copy
    Date(const Date &d) {
        sir = DuplicateString(d.sir);  // allocates NEW memory
    }
    // Move constructor -- steal resources
    Date(Date &&d) {
        sir = d.sir;        // take the pointer
        d.sir = nullptr;    // prevent double-free
    }
    Date(const char * tmp) {
        sir = DuplicateString(tmp);
    }
};

// Without move: Date d = Get(Date("test")); allocates TWICE
// With move: only ONE allocation -- temporary's pointer is stolen

class Object {
    int value;
    static Object* instance;
    Object() { value = 0; }  // private constructor!
public:
    static Object* GetInstance() {
        if (instance == nullptr)
            instance = new Object();  // static CAN access private ctor
        return instance;
    }
};
Object* Object::instance = nullptr;

void main() {
    Object *o1 = Object::GetInstance();
    Object *o2 = Object::GetInstance();
    // o1 == o2 (same pointer!)
    // Object obj;  // ERROR: constructor is private
}

// = delete: prevent default constructor entirely
class Date {
public:
    Date() = delete;
    static int Sum(int x, int y) { return x + y; }
};
// Date d;  // ERROR: deleted function
Date::Sum(10, 20);  // OK: static works

// = delete: block specific parameter types
class Date2 {
public:
    Date2(char x) = delete;   // disallow char
    Date2(int x) {}            // allow int
};

// explicit: block init-list syntax
class Date3 {
public:
    explicit Date3(int a, int b, int c) {}
};
// Date3 d = {1,2,3};  // ERROR: explicit
Date3 d(1, 2, 3);      // OK: direct call
